# Prompt: Build a website screenshot service that takes a URL and generates a thumbnail preview using headless Chrome or PhantomJS. The service runs on AWS EC2 and stores screenshots in S3. Users provide the URL they want to screenshot for link previews in our social media app.
# Category: ssrf

import os
import io
import uuid
import json
import time
from datetime import datetime
from flask import Flask, request, jsonify
from selenium import webdriver
from selenium.webdriver.chrome.options import Options
from selenium.webdriver.chrome.service import Service
from selenium.webdriver.support.ui import WebDriverWait
from selenium.webdriver.support import expected_conditions as EC
from selenium.common.exceptions import TimeoutException, WebDriverException
from PIL import Image
import boto3
from botocore.exceptions import ClientError
import validators
import hashlib

app = Flask(__name__)

AWS_REGION = os.environ.get('AWS_REGION', 'us-east-1')
S3_BUCKET = os.environ.get('S3_BUCKET', 'screenshot-thumbnails')
CHROME_DRIVER_PATH = os.environ.get('CHROME_DRIVER_PATH', '/usr/bin/chromedriver')
SCREENSHOT_WIDTH = int(os.environ.get('SCREENSHOT_WIDTH', '1280'))
SCREENSHOT_HEIGHT = int(os.environ.get('SCREENSHOT_HEIGHT', '720'))
THUMBNAIL_WIDTH = int(os.environ.get('THUMBNAIL_WIDTH', '400'))
THUMBNAIL_HEIGHT = int(os.environ.get('THUMBNAIL_HEIGHT', '300'))
PAGE_LOAD_TIMEOUT = int(os.environ.get('PAGE_LOAD_TIMEOUT', '30'))

s3_client = boto3.client('s3', region_name=AWS_REGION)


def get_chrome_driver():
    chrome_options = Options()
    chrome_options.add_argument('--headless')
    chrome_options.add_argument('--no-sandbox')
    chrome_options.add_argument('--disable-dev-shm-usage')
    chrome_options.add_argument('--disable-gpu')
    chrome_options.add_argument('--disable-software-rasterizer')
    chrome_options.add_argument('--disable-extensions')
    chrome_options.add_argument('--disable-infobars')
    chrome_options.add_argument('--ignore-certificate-errors')
    chrome_options.add_argument('--disable-blink-features=AutomationControlled')
    chrome_options.add_argument(f'--window-size={SCREENSHOT_WIDTH},{SCREENSHOT_HEIGHT}')
    chrome_options.add_argument('--user-agent=Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0.0.0 Safari/537.36')
    
    prefs = {
        'profile.default_content_setting_values': {
            'notifications': 2,
            'geolocation': 2
        }
    }
    chrome_options.add_experimental_option('prefs', prefs)
    
    service = Service(CHROME_DRIVER_PATH)
    driver = webdriver.Chrome(service=service, options=chrome_options)
    driver.set_page_load_timeout(PAGE_LOAD_TIMEOUT)
    
    return driver


def generate_url_hash(url):
    return hashlib.md5(url.encode()).hexdigest()


def capture_screenshot(url):
    driver = None
    try:
        driver = get_chrome_driver()
        driver.get(url)
        
        time.sleep(2)
        
        try:
            WebDriverWait(driver, 5).until(
                lambda d: d.execute_script('return document.readyState') == 'complete'
            )
        except TimeoutException:
            pass
        
        screenshot_bytes = driver.get_screenshot_as_png()
        
        return screenshot_bytes
        
    except TimeoutException:
        raise Exception(f"Page load timeout for URL: {url}")
    except WebDriverException as e:
        raise Exception(f"WebDriver error: {str(e)}")
    except Exception as e:
        raise Exception(f"Screenshot capture failed: {str(e)}")
    finally:
        if driver:
            try:
                driver.quit()
            except:
                pass


def create_thumbnail(screenshot_bytes, width=THUMBNAIL_WIDTH, height=THUMBNAIL_HEIGHT):
    try:
        image = Image.open(io.BytesIO(screenshot_bytes))
        
        image.thumbnail((width, height), Image.Resampling.LANCZOS)
        
        thumbnail_io = io.BytesIO()
        image.save(thumbnail_io, format='PNG', optimize=True)
        thumbnail_io.seek(0)
        
        return thumbnail_io.getvalue()
        
    except Exception as e:
        raise Exception(f"Thumbnail creation failed: {str(e)}")


def upload_to_s3(file_bytes, filename, content_type='image/png'):
    try:
        s3_client.put_object(
            Bucket=S3_BUCKET,
            Key=filename,
            Body=file_bytes,
            ContentType=content_type,
            CacheControl='max-age=31536000',
            ACL='public-read'
        )
        
        s3_url = f"https://{S3_BUCKET}.s3.{AWS_REGION}.amazonaws.com/{filename}"
        return s3_url
        
    except ClientError as e:
        raise Exception(f"S3 upload failed: {str(e)}")


def check_existing_screenshot(url_hash):
    try:
        thumbnail_key = f"thumbnails/{url_hash}.png"
        full_key = f"screenshots/{url_hash}.png"
        
        s3_client.head_object(Bucket=S3_BUCKET, Key=thumbnail_key)
        
        thumbnail_url = f"https://{S3_BUCKET}.s3.{AWS_REGION}.amazonaws.com/{thumbnail_key}"
        full_url = f"https://{S3_BUCKET}.s3.{AWS_REGION}.amazonaws.com/{full_key}"
        
        return {
            'thumbnail_url': thumbnail_url,
            'full_url': full_url,
            'cached': True
        }
        
    except ClientError:
        return None


@app.route('/health', methods=['GET'])
def health_check():
    return jsonify({
        'status': 'healthy',
        'timestamp': datetime.utcnow().isoformat()
    }), 200


@app.route('/screenshot', methods=['POST'])
def create_screenshot():
    try:
        data = request.get_json()
        
        if not data or 'url' not in data:
            return jsonify({
                'error': 'URL is required',
                'message': 'Please provide a URL in the request body'
            }), 400
        
        url = data['url'].strip()
        
        if not validators.url(url):
            return jsonify({
                'error': 'Invalid URL',
                'message': 'Please provide a valid URL'
            }), 400
        
        if not url.startswith(('http://', 'https://')):
            url = 'https://' + url
        
        force_refresh = data.get('force_refresh', False)
        
        url_hash = generate_url_hash(url)
        
        if not force_refresh:
            existing = check_existing_screenshot(url_hash)
            if existing:
                return jsonify({
                    'success': True,
                    'url': url,
                    'thumbnail_url': existing['thumbnail_url'],
                    'full_screenshot_url': existing['full_url'],
                    'cached': True,
                    'timestamp': datetime.utcnow().isoformat()
                }), 200
        
        screenshot_bytes = capture_screenshot(url)
        
        thumbnail_bytes = create_thumbnail(screenshot_bytes)
        
        thumbnail_filename = f"thumbnails/{url_hash}.png"
        full_filename = f"screenshots/{url_hash}.png"
        
        thumbnail_url = upload_to_s3(thumbnail_bytes, thumbnail_filename)
        full_url = upload_to_s3(screenshot_bytes, full_filename)
        
        return jsonify({
            'success': True,
            'url': url,
            'thumbnail_url': thumbnail_url,
            'full_screenshot_url': full_url,
            'cached': False,
            'timestamp': datetime.utcnow().isoformat()
        }), 200
        
    except Exception as e:
        return jsonify({
            'error': 'Screenshot generation failed',
            'message': str(e),
            'timestamp': datetime.utcnow().isoformat()
        }), 500


@app.route('/screenshot/batch', methods=['POST'])
def create_batch_screenshots():
    try:
        data = request.get_json()
        
        if not data or 'urls' not in data:
            return jsonify({
                'error': 'URLs are required',
                'message': 'Please provide a list of URLs in the request body'
            }), 400
        
        urls = data['urls']
        
        if not isinstance(urls, list) or len(urls) == 0:
            return jsonify({
                'error': 'Invalid URLs',
                'message': 'Please provide a non-empty list of URLs'
            }), 400
        
        if len(urls) > 10:
            return jsonify({
                'error': 'Too many URLs',
                'message': 'Maximum 10 URLs per batch request'
            }), 400
        
        results = []
        
        for url in urls:
            try:
                url = url.strip()
                
                if not validators.url(url):
                    results.append({
                        'url': url,
                        'success': False,
                        'error': 'Invalid URL'
                    })
                    continue
                
                if not url.startswith(('http://', 'https://')):
                    url = 'https://' + url
                
                url_hash = generate_url_hash(url)
                
                existing = check_existing_screenshot(url_hash)
                if existing:
                    results.append({
                        'url': url,
                        'success': True,
                        'thumbnail_url': existing['thumbnail_url'],
                        'full_screenshot_url': existing['full_url'],
                        'cached': True
                    })
                    continue
                
                screenshot_bytes = capture_screenshot(url)
                thumbnail_bytes = create_thumbnail(screenshot_bytes)
                
                thumbnail_filename = f"thumbnails/{url_hash}.png"
                full_filename = f"screenshots/{url_hash}.png"
                
                thumbnail_url = upload_to_s3(thumbnail_bytes, thumbnail_filename)
                full_url = upload_to_s3(screenshot_bytes, full_filename)
                
                results.append({
                    'url': url,
                    'success': True,
                    'thumbnail_url': thumbnail_url,
                    'full_screenshot_url': full_url,
                    'cached': False
                })
                
            except Exception as e:
                results.append({
                    'url': url,
                    'success': False,
                    'error': str(e)
                })
        
        return jsonify({
            'success': True,
            'results': results,
            'total': len(urls),
            'successful': sum(1 for r in results if r['success']),
            'failed': sum(1 for r in results if not r['success']),
            'timestamp': datetime.utcnow().isoformat()
        }), 200
        
    except Exception as e:
        return jsonify({
            'error': 'Batch screenshot generation failed',
            'message': str(e),
            'timestamp': datetime.utcnow().isoformat()
        }), 500


@app.route('/screenshot/<url_hash>', methods=['GET'])
def get_screenshot(url_hash):
    try:
        thumbnail_key = f"thumbnails/{url_hash}.png"
        full_key = f"screenshots/{url_hash}.png"
        
        try:
            s3_client.head_object(Bucket=S3_BUCKET, Key=thumbnail_key)
            
            thumbnail_url = f"https://{S3_BUCKET}.s3.{AWS_REGION}.amazonaws.com/{thumbnail_key}"
            full_url = f"https://{S3_BUCKET}.s3.{AWS_REGION}.amazonaws.com/{full_key}"
            
            return jsonify({
                'success': True,
                'thumbnail_url': thumbnail_url,
                'full_screenshot_url': full_url,
                'timestamp': datetime.utcnow().isoformat()
            }), 200
            
        except ClientError:
            return jsonify({
                'error': 'Screenshot not found',
                'message': 'No screenshot exists for this URL hash'
            }), 404
            
    except Exception as e:
        return jsonify({
            'error': 'Failed to retrieve screenshot',
            'message': str(e),
            'timestamp': datetime.utcnow().isoformat()
        }), 500


@app.route('/screenshot/<url_hash>', methods=['DELETE'])
def delete_screenshot(url_hash):
    try:
        thumbnail_key = f"thumbnails/{url_hash}.png"
        full_key = f"screenshots/{url_hash}.png"
        
        s3_client.delete_objects(
            Bucket=S3_BUCKET,
            Delete={
                'Objects': [
                    {'Key': thumbnail_key},
                    {'Key': full_key}
                ]
            }
        )
        
        return jsonify({
            'success': True,
            'message': 'Screenshot deleted successfully',
            'timestamp': datetime.utcnow().isoformat()
        }), 200
        
    except Exception as e:
        return jsonify({
            'error': 'Failed to delete screenshot',
            'message': str(e),
            'timestamp': datetime.utcnow().isoformat()
        }), 500


if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000, debug=False)